import type * as React from 'react';

import {cn} from '@/lib/utils';

import {Circle} from 'lucide-react';
import {RadioGroup as RadioGroupPrimitive} from 'radix-ui';

/**
 * A set of checkable buttons--known as radio buttons--where no more than one of the buttons can be checked at a time.
 *
 * ### Component Props
 *
 * See [Radio Group props](https://www.radix-ui.com/primitives/docs/components/radio-group) documentation for full details.
 *
 * | Prop             | Type                         | Default     |
 * | :--------------- | :--------------------------- | :---------- |
 * | _asChild_        | `boolean`                    | `false`     |
 * | _defaultValue_   | `string`                     | -           |
 * | _value_          | `string`                     | -           |
 * | _onValueChange_  | `(value: string) => void`    | -           |
 * | _disabled_       | `boolean`                    | -           |
 * | _name_           | `string`                     | -           |
 * | _required_       | `boolean`                    | -           |
 * | _orientation_    | `"vertical" \| "horizontal"` | -           |
 * | _dir_            | `"ltr" \| "rtl"`             | -           |
 * | _loop_           | `boolean`                    | `true`      |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <RadioGroup defaultValue="option-1">
 *   <div className="flex items-center space-x-2">
 *     <RadioGroupItem value="option-1" id="option-1" />
 *     <Label htmlFor="option-1">Option 1</Label>
 *   </div>
 *   <div className="flex items-center space-x-2">
 *     <RadioGroupItem value="option-2" id="option-2" />
 *     <Label htmlFor="option-2">Option 2</Label>
 *   </div>
 * </RadioGroup>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 4.1.2 Name, Role, Value — semantic `radiogroup` role via Radix RadioGroup primitive.
 * @wcag 2.1.1 Keyboard — arrow keys navigate between items; Space selects.
 * @wcag 2.4.7 Focus Visible — focus ring on items via `focus-visible:ring-3`.
 * @wcag 1.3.1 Info and Relationships — group structure conveyed via `role="radiogroup"` and individual `role="radio"`.
 */
function RadioGroup({
  className,
  ...props
}: React.ComponentProps<typeof RadioGroupPrimitive.Root>) {
  return (
    <RadioGroupPrimitive.Root
      data-slot="radio-group"
      className={cn('grid w-full gap-3', className)}
      {...props}
    />
  );
}

/**
 * An individual radio button item within a RadioGroup.
 *
 * ### Component Props
 *
 * See [Radio Group Item props](https://www.radix-ui.com/primitives/docs/components/radio-group) documentation for full details.
 *
 * | Prop              | Type      | Default |
 * | :---------------- | :-------- | :------ |
 * | _asChild_         | `boolean` | `false` |
 * | _value_ *(required)* | `string`  | -       |
 * | _disabled_        | `boolean` | -       |
 * | _required_        | `boolean` | -       |
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <RadioGroupItem value="option-1" id="option-1" />
 * ```
 */
function RadioGroupItem({
  className,
  ...props
}: React.ComponentProps<typeof RadioGroupPrimitive.Item>) {
  return (
    <RadioGroupPrimitive.Item
      data-slot="radio-group-item"
      className={cn(
        'group/radio-group-item peer relative flex aspect-square size-4 shrink-0 rounded-full border border-input text-primary shadow-raised outline-none after:absolute after:-inset-x-3 after:-inset-y-2 focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring disabled:cursor-not-allowed disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 dark:bg-input-bg dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40',
        className
      )}
      {...props}
    >
      <RadioGroupPrimitive.Indicator
        data-slot="radio-group-indicator"
        className="flex size-4 items-center justify-center text-primary group-aria-invalid/radio-group-item:text-destructive"
      >
        <Circle className="absolute top-1/2 left-1/2 size-2 -translate-x-1/2 -translate-y-1/2 fill-current" />
      </RadioGroupPrimitive.Indicator>
    </RadioGroupPrimitive.Item>
  );
}

export {RadioGroup, RadioGroupItem};
